// Array tiplərinin sintaksisi
let numbers: number[] = [1, 2, 3];
let names: Array<string> = ['Ali', 'Vəli', 'Ayşə'];

console.log(numbers); // [1, 2, 3]
console.log(names); // ['Ali', 'Vəli', 'Ayşə']
// numbers.push('dörd'); // Xəta: string number[]-ə əlavə edilə bilməz

// Çoxölçülü massivlər
let matrix: number[][] = [[1, 2], [3, 4], [5, 6]];

console.log(matrix); // [[1, 2], [3, 4], [5, 6]]
console.log(matrix[0][1]); // 2
// matrix.push(['yedi']); // Xəta: string[] number[][]-ə əlavə edilə bilməz

// Readonly massivlər
let readOnlyNumbers: readonly number[] = [1, 2, 3];

console.log(readOnlyNumbers); // [1, 2, 3]
// readOnlyNumbers.push(4); // Xəta: readonly massivə əlavə etmək olmur

// Massiv metodları
let scores: number[] = [10, 20, 30];

scores.push(40);
console.log(scores); // [10, 20, 30, 40]

let doubled: number[] = scores.map(score => score * 2);
console.log(doubled); // [20, 40, 60, 80]

let highScores: number[] = scores.filter(score => score > 20);
console.log(highScores); // [30, 40]
// scores.push('elli'); // Xəta: string number[]-ə əlavə edilə bilməz

// Union tipləri ilə massivlər
let mixed: (string | number)[] = ['apple', 5, 'banana', 10];

console.log(mixed); // ['apple', 5, 'banana', 10]
// mixed.push(true); // Xəta: boolean union tipinə uyğun deyil

// Tuple tipləri
let person: [string, number] = ['Ali', 25];

console.log(person); // ['Ali', 25]
// person = ['Vəli', 30, true]; // Xəta: tuple yalnız iki element qəbul edir
// person[0] = 42; // Xəta: number string-ə təyin edilə bilməz

// Praktik nümunə
interface Product {
  id: number;
  name: string;
  price: number;
}

let products: Product[] = [
  { id: 1, name: 'Telefon', price: 500 },
  { id: 2, name: 'Laptop', price: 1000 },
];

function displayProducts(products: Product[]): void {
  products.forEach(product => {
    console.log(`Məhsul: ${product.name}, Qiymət: ${product.price}`);
  });
}

displayProducts(products);
// Çıxış:
// Məhsul: Telefon, Qiymət: 500
// Məhsul: Laptop, Qiymət: 1000

// Təhlükəsizlik nümunəsi
let values: (string | number)[] = ['test', 42];

if (typeof values[0] === 'string') {
  console.log(values[0].toUpperCase()); // TEST
}
// values.push(true); // Xəta: boolean union tipinə uyğun deyil

// Səhvə yol açan nümunə
let unsafe: any[] = ['Hello', 42];
unsafe.push(true); // Təhlükəsiz deyil, runtime səhvi ola bilər
console.log(unsafe); // ['Hello', 42, true]

// Düzgün yol
let safe: string[] = ['Hello'];
console.log(safe); // ['Hello']
// safe.push(42); // Xəta: number string[]-ə əlavə edilə bilməz

// Real layihə ssenarisi
function filterExpensiveProducts(products: Product[], minPrice: number): Product[] {
  return products.filter(product => product.price > minPrice);
}

let products: Product[] = [
  { id: 1, name: 'Telefon', price: 500 },
  { id: 2, name: 'Laptop', price: 1000 },
  { id: 3, name: 'Planşet', price: 300 },
];

let expensive: Product[] = filterExpensiveProducts(products, 500);
console.log(expensive); // [{ id: 2, name: 'Laptop', price: 1000 }]

