// Array type syntax
let numbers: number[] = [1, 2, 3];
let names: Array<string> = ['Alice', 'Bob', 'Eve'];

console.log(numbers); // [1, 2, 3]
console.log(names); // ['Alice', 'Bob', 'Eve']
// numbers.push('four'); // Error: string cannot be added to number[]

// Multidimensional arrays
let matrix: number[][] = [[1, 2], [3, 4], [5, 6]];

console.log(matrix); // [[1, 2], [3, 4], [5, 6]]
console.log(matrix[0][1]); // 2
// matrix.push(['seven']); // Error: string[] cannot be added to number[][]

// Readonly arrays
let readOnlyNumbers: readonly number[] = [1, 2, 3];

console.log(readOnlyNumbers); // [1, 2, 3]
// readOnlyNumbers.push(4); // Error: cannot push to readonly array

// Array methods
let scores: number[] = [10, 20, 30];

scores.push(40);
console.log(scores); // [10, 20, 30, 40]

let doubled: number[] = scores.map(score => score * 2);
console.log(doubled); // [20, 40, 60, 80]

let highScores: number[] = scores.filter(score => score > 20);
console.log(highScores); // [30, 40]
// scores.push('fifty'); // Error: string cannot be added to number[]

// Arrays with union types
let mixed: (string | number)[] = ['apple', 5, 'banana', 10];

console.log(mixed); // ['apple', 5, 'banana', 10]
// mixed.push(true); // Error: boolean is not part of union type

// Tuple types
let person: [string, number] = ['Alice', 25];

console.log(person); // ['Alice', 25]
// person = ['Bob', 30, true]; // Error: tuple expects only two elements
// person[0] = 42; // Error: number cannot be assigned to string

// Practical example
interface Product {
  id: number;
  name: string;
  price: number;
}

let products: Product[] = [
  { id: 1, name: 'Phone', price: 500 },
  { id: 2, name: 'Laptop', price: 1000 },
];

function displayProducts(products: Product[]): void {
  products.forEach(product => {
    console.log(`Product: ${product.name}, Price: ${product.price}`);
  });
}

displayProducts(products);
// Output:
// Product: Phone, Price: 500
// Product: Laptop, Price: 1000

// Security example
let values: (string | number)[] = ['test', 42];

if (typeof values[0] === 'string') {
  console.log(values[0].toUpperCase()); // TEST
}
// values.push(true); // Error: boolean is not part of union type

// Error-prone example
let unsafe: any[] = ['Hello', 42];
unsafe.push(true); // Unsafe, may cause runtime errors
console.log(unsafe); // ['Hello', 42, true]

// Correct approach
let safe: string[] = ['Hello'];
console.log(safe); // ['Hello']
// safe.push(42); // Error: number cannot be added to string[]

// Real-world scenario
function filterExpensiveProducts(products: Product[], minPrice: number): Product[] {
  return products.filter(product => product.price > minPrice);
}

let products: Product[] = [
  { id: 1, name: 'Phone', price: 500 },
  { id: 2, name: 'Laptop', price: 1000 },
  { id: 3, name: 'Tablet', price: 300 },
];

let expensive: Product[] = filterExpensiveProducts(products, 500);
console.log(expensive); // [{ id: 2, name: 'Laptop', price: 1000 }]

